十进制与八进制的转换
1.格式控制（直接输出）
格式控制包括格式说明和格式字符。

格式说明由“％”和格式字符组成，如％d、％f等。它的作用是将输出的数据转换为指定的格式输出。格式说明总是由“％”字符开始的。不同类型的数据用不同的格式字符。

&#x3D;&#x3D;％d为整型输出；％o以八进制数形式输出整数。&#x3D;&#x3D;


c#include&lt;stdio.h&gt;

int main(void)
&#123;
    int n;
    scanf(&quot;%d&quot;,&amp;n);
    printf(&quot;%o&quot;,n);
    return 0;
&#125;
2.除k取余法（循环）
通过利用循环来实现除k取余法，是比较常见的一种进制转换的方式。

c#include&lt;stdio.h&gt;
#include&lt;math.h&gt;

int main(void)
&#123;
    int n,temp,sum=0,i=0;
    scanf(&quot;%d&quot;,&amp;n);
    while(n)
    &#123;
        temp = n%8;
        n = n/8;
        sum += temp*pow(10,i);
        i++;
    &#125;
    printf(&quot;%d&quot;,sum);
    return 0;
&#125;
3.字符串版
利用字符串的特性来实现进制转换。

c#include&lt;stdio.h&gt;
#include&lt;string.h&gt;
#define N 100

void change (char str[N],int n);
int main(void)
&#123;
    char str[N];
    int n;
    scanf(&quot;%d&quot;,&amp;n);
    change(str,n);
    puts(str);
    return 0; 
&#125;
void change (char str[N],int n)
&#123;
    int i=0;
    while(n)
    &#123;
        str[i]=n%8+&#39;0&#39;;
        i++;
        n/=8;
    &#125;
    str[i]=&#39;\0&#39;;
    strrev(str);
&#125;

4.指针法
结合循环、字符串、指针来实现进制转换。

c#include&lt;stdio.h&gt;
#include&lt;string.h&gt;
#define N 100

void change (char str[N],int n);
int main(void)
&#123;
    char str[N];
    int n;
    scanf(&quot;%d&quot;,&amp;n);
    change(str,n);
    puts(str);
    return 0; 
&#125;
void change (char str[N],int n)
&#123;
    int i=0,d;
    while(n)
    &#123;
        d = n%8;
        str[i]=&quot;0123456789abcdef&quot;[d];
        i++;
        n/=8;
    &#125;
    str[i]=&#39;\0&#39;;
    strrev(str);
&#125;
